\begin{remark}[Use in Serre finiteness]
  Together with iteration~037's \lstinline{module_finite_HModule_of_HModule'_X₄} (the analogue at general degree $n$ via the corner-bridge), the project now has the complete algebraic-to-cohomological $\Module.\mathrm{Finite}$ transport infrastructure at degree $0$ (no Mayer-Vietoris LES required) and at any degree via the corner-bridge (Mayer-Vietoris LES required for the geometric inputs). The substantive geometric inputs (Serre vanishing on affines, finiteness of the Hom-from-constant-sheaf for proper schemes) remain queued for iter-040+ (multi-iteration assembly required since Mathlib still lacks scheme-level Serre vanishing).
\end{remark}

\section{Curve specialisations of the $H^0$ $\Module\,k$-finite transports (iter-039)}
\label{sec:HModule_finite_zero_curve_iter039}

After Theorems~\ref{thm:Scheme_module_finite_HModule_zero} and~\ref{thm:Scheme_module_finite_HModule_prime_zero} the iter-038 H⁰ $\Module\,k$-finite transports cover the abstract sheaf setting. Iter-039 lands their direct curve specialisations to $F := \toModuleKSheaf\,C$ for $C : \Over\,(\Spec\,(\CommRingCat.\mathrm{of}\,k))$, completing the $\Module\,k$-finite transport ladder at degree $0$ for the curve setting and setting up the iter-040+ Hom-from-affine-evaluation finiteness inputs the cover-evaluation chain consumes.
The bodies are pure dot-notation method-call wrappers around iter-038's transports; they rely on the iter-005 instances $\HasSheafify\,(\Opens.\gT\,C.\mathtt{left}.\toTopCat)\,(\ModuleCat\,k)$ and $\HasExt$ on the corresponding sheaf category being auto-resolved by \lstinline{inferInstance}.

\begin{theorem}\leanok
[Curve specialisation of the $\HModule\,k\,F\,0$ $\Module\,k$-finite transport]
  \label{thm:Scheme_module_finite_HModule_zero_curve}
  \lean{AlgebraicGeometry.Scheme.module_finite_HModule_zero_curve}
  \uses{thm:Scheme_module_finite_HModule_zero, def:Scheme_toModuleKSheaf}
  Let $k$ be a field and $C : \Over\,(\Spec\,(\CommRingCat.\mathrm{of}\,k))$. If the $k$-linear Hom group $((\mathtt{constantSheaf}\,(\Opens.\gT\,C.\mathtt{left}.\toTopCat)\,(\ModuleCat\,k)).\mathrm{obj}\,(\ModuleCat.\mathrm{of}\,k\,k) \to \toModuleKSheaf\,C)$ is $\Module.\mathrm{Finite}$ over $k$, then $\HModule\,k\,(\toModuleKSheaf\,C)\,0$ is $\Module.\mathrm{Finite}$ over $k$.
\end{theorem}

\begin{proof}
  \uses{thm:Scheme_module_finite_HModule_zero}
  \leanok
  Direct dot-notation method-call \lstinline{Scheme.module_finite_HModule_zero k _}: the abstract Theorem~\ref{thm:Scheme_module_finite_HModule_zero} is applied with $J := \Opens.\gT\,C.\mathtt{left}.\toTopCat$ (auto-inferred via the iter-005 \lstinline{instHasSheafify_Opens_ModuleCatK} and \lstinline{instHasExt_Sheaf_Opens_ModuleCatK} instances) and $F := \toModuleKSheaf\,C$ (filled by \lstinline{_} from the result type). The typeclass-style hypothesis on the Hom group is propagated unchanged.
\end{proof}

\begin{theorem}\leanok
[Curve specialisation of the $\HModulePrime\,k\,F\,0\,U$ $\Module\,k$-finite transport]
  \label{thm:Scheme_module_finite_HModule_prime_zero_curve}
  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_zero_curve}
  \uses{thm:Scheme_module_finite_HModule_prime_zero, def:Scheme_toModuleKSheaf}
  Let $k$ be a field, $C : \Over\,(\Spec\,(\CommRingCat.\mathrm{of}\,k))$, and $U$ an open of $C.\mathtt{left}.\toTopCat$. If the $k$-linear Hom group $((\mathtt{presheafToSheaf}\,(\Opens.\gT\,C.\mathtt{left}.\toTopCat)\,(\ModuleCat\,k)).\mathrm{obj}\,((\yoneda \circ \free_k).\mathrm{obj}\,U) \to \toModuleKSheaf\,C)$ is $\Module.\mathrm{Finite}$ over $k$, then $\HModulePrime\,k\,(\toModuleKSheaf\,C)\,0\,U$ is $\Module.\mathrm{Finite}$ over $k$.
\end{theorem}

\begin{proof}
  \uses{thm:Scheme_module_finite_HModule_prime_zero}
  \leanok
  Direct dot-notation method-call \lstinline{Scheme.module_finite_HModule'_zero k _ U}: the abstract Theorem~\ref{thm:Scheme_module_finite_HModule_prime_zero} is applied with the same auto-inferred topology / instance setup as Theorem~\ref{thm:Scheme_module_finite_HModule_zero_curve}, with $X := U$ and $F := \toModuleKSheaf\,C$. The Hom-group hypothesis is propagated unchanged.
\end{proof}

\begin{remark}[Use in the cover-evaluation chain]
  For an affine cover $X = U_1 \cup U_2$ packaged as an \lstinline{AffineCoverMVSquare} (iter-028), the four corners of the Mayer-Vietoris square are $X_1 = U_1$, $X_2 = U_2$, $X_3 = U_1 \cap U_2$, $X_4 = \top$. The iter-029/030 LES on $\HModulePrime\,k\,(\toModuleKSheaf\,C)$ at degrees $(0, 1)$ then reads
  \[
    \HModulePrime^0(X_4) \to \HModulePrime^0(X_2) \oplus \HModulePrime^0(X_3) \to \HModulePrime^0(X_1) \to \HModulePrime^1(X_4) \to \cdots
  \]
  The iter-035 corner-bridge identifies $\HModulePrime^n(X_4)$ with $\HModule\,k\,(\toModuleKSheaf\,C)\,n$. After future affine vanishing (Mathlib gap; queued for iter-040+), $\HModulePrime^1(X_2) = \HModulePrime^1(X_3) = 0$, so the LES yields a short exact sequence presenting $\HModule^1$ as a cokernel of $\HModulePrime^0(X_2) \oplus \HModulePrime^0(X_3) \to \HModulePrime^0(X_1)$. The iter-039 curve specialisations~\ref{thm:Scheme_module_finite_HModule_zero_curve} and~\ref{thm:Scheme_module_finite_HModule_prime_zero_curve} then propagate $\Module\,k$-finiteness through the H⁰ pieces (one application per affine corner), and iter-037's \lstinline{module_finite_HModule_of_HModule'_X₄_curve} carries the result up to $\HModule\,k\,(\toModuleKSheaf\,C)\,1$, which is the genus carrier (Definition~\ref{def:genus_alg}).
\end{remark}

